    48	/* Generic function to find the peak of channel estimation buffer */
    49	void peak_estimator(int32_t *buffer, int32_t buf_len, int32_t *peak_idx, int32_t *peak_val, int32_t mean_val)
    50	{
    51	  int32_t max_val = 0, max_idx = 0, abs_val = 0;
    52	  for(int k = 0; k < buf_len; k++)
    53	  {
    54	    abs_val = squaredMod(((c16_t*)buffer)[k]);
    55	    if(abs_val > max_val)
    56	    {
    57	      max_val = abs_val;
    58	      max_idx = k;
    59	    }
    60	  }
    61	
    62	  // Check for detection threshold
    63	  LOG_D(PHY, "PRS ToA estimator: max_val %d, mean_val %d, max_idx %d\n", max_val, mean_val, max_idx);
    64	  if ((mean_val != 0) && (max_val / mean_val > 10)) {
    65	    *peak_val = max_val;
    66	    *peak_idx = max_idx;
    67	  } else {
    68	    *peak_val = 0;
    69	    *peak_idx = 0;
    70	  }
    71	}
